    public GameObject happyBobby;    // Referencia al sprite/animación feliz
    public Text messageText;        // Texto para mostrar el mensaje
    public float messageDuration = 5f; // Duración del mensaje en segundos

    void Update()
    {
        // Ejemplo: Verificar si el usuario tiene el ítem premium
        if (!PlayerPrefs.HasKey("hasPremiumItem") || !PlayerPrefs.GetInt("hasPremiumItem"))
